do function LoadMainScript() local Players=game:GetService("Players");local ReplicatedStorage=game:GetService("ReplicatedStorage");local StarterPack=game:GetService("StarterPack");local RunService=game:GetService("RunService");local UserInputService=game:GetService("UserInputService");local Camera=workspace.CurrentCamera;local LocalPlayer=Players.LocalPlayer;local espEnabled=true;local aimbotEnabled=true;local antiShakeEnabled=true;local MAX_DISTANCE=2000;local UPDATE_INTERVAL=0.5;local BillboardCache={};local nameCache={};local ProtectedFriends={};local AIM_SMOOTHNESS=0.85;local AIM_RANGE=300;local FOV_RADIUS=120;local FOVCircle=Drawing.new("Circle");FOVCircle.Radius=FOV_RADIUS;FOVCircle.Thickness=2;FOVCircle.Color=Color3.fromRGB(255,50,50);FOVCircle.Transparency=0.6;FOVCircle.Filled=false;FOVCircle.Visible=true;local function StabilizeWeapon(weapon) if  not antiShakeEnabled then return;end if (weapon and weapon:IsA("Tool")) then pcall(function() local currentRecoil=weapon:GetAttribute("Recoil") or 1 ;weapon:SetAttribute("Recoil",currentRecoil * 0.4 );weapon:SetAttribute("Kickback",0);weapon:SetAttribute("CameraShake",0);weapon:SetAttribute("Spread",0.3);end);end end local function MonitorWeapon() local character=LocalPlayer.Character;if  not character then return;end local currentWeapon=character:FindFirstChildOfClass("Tool");if currentWeapon then StabilizeWeapon(currentWeapon);end character.ChildAdded:Connect(function(child) if child:IsA("Tool") then task.wait(0.1);StabilizeWeapon(child);end end);end local WEAPON_COLORS={Legendary=Color3.fromRGB(255,215,0),Epic=Color3.fromRGB(200,0,255),Rare=Color3.fromRGB(0,150,255),Uncommon=Color3.fromRGB(0,255,100),Common=Color3.fromRGB(200,200,200)};local function GetWeaponRarity(tool) local rarity=tool:GetAttribute("RarityName") or tool:GetAttribute("Rarity") ;if (rarity and WEAPON_COLORS[rarity]) then return rarity,WEAPON_COLORS[rarity];end local name=tool.Name:lower();if (name:find("legendary") or name:find("mythic")) then return "Legendary",WEAPON_COLORS['Legendary'];elseif name:find("epic") then return "Epic",WEAPON_COLORS['Epic'];elseif name:find("rare") then return "Rare",WEAPON_COLORS['Rare'];elseif name:find("uncommon") then return "Uncommon",WEAPON_COLORS['Uncommon'];else return "Common",WEAPON_COLORS['Common'];end end local function getRealName(t) if ( not t or  not t.Name) then return nil;end local originalName=t.Name;local lowerName=originalName:lower();local cleaned=lowerName:gsub("%d+$",""):gsub("_%d+$",""):gsub("%s*%d+%s*$",""):gsub("[%s_]+"," "):gsub("([^%w%s])",""):match("^%s*(.-)%s*$");if (cleaned:find("fishing") or cleaned:find("rod") or cleaned:find("canne")) then if cleaned:find("ultimate") then return "Ultimate Fishing Rod";elseif cleaned:find("advanced") then return "Advanced Fishing Rod";elseif cleaned:find("pro") then return "Pro Fishing Rod";else return "Fishing Rod";end end if nameCache[originalName] then return nameCache[originalName];end local h=t:FindFirstChild("Handle");local fallbackName=cleaned:gsub("^%l",string.upper);for _,folder in ipairs({ReplicatedStorage:FindFirstChild("Items"),StarterPack}) do if folder then for _,item in ipairs(folder:GetDescendants()) do if (item:IsA("Tool") and item:FindFirstChild("Handle")) then local match=true;if h then for _,c in ipairs(h:GetChildren()) do if  not item.Handle:FindFirstChild(c.Name) then match=false;break;end end else match=false;end if match then nameCache[originalName]=item.Name;return item.Name;end end end end end nameCache[originalName]=fallbackName;return fallbackName;end local function updateESP(p) local bb=BillboardCache[p];if  not bb then return;end if  not espEnabled then bb.Enabled=false;return;end local char=p.Character;if ( not char or  not char:FindFirstChild("HumanoidRootPart")) then bb.Enabled=false;return;end local lChar=LocalPlayer.Character;if (lChar and lChar:FindFirstChild("HumanoidRootPart")) then local dist=(lChar.HumanoidRootPart.Position-char.HumanoidRootPart.Position).Magnitude;if (dist>MAX_DISTANCE) then bb.Enabled=false;return;end end local container=bb:FindFirstChild("EspContainer");if  not container then return;end container:ClearAllChildren();local layout=Instance.new("UIListLayout",container);layout.HorizontalAlignment=Enum.HorizontalAlignment.Center;layout.VerticalAlignment=Enum.VerticalAlignment.Top;layout.Padding=UDim.new(0,3);local nameLabel=Instance.new("TextLabel",container);nameLabel.Size=UDim2.new(0,180,0,18);nameLabel.BackgroundTransparency=0.4;nameLabel.BackgroundColor3=Color3.fromRGB(0,0,0);nameLabel.Text=p.DisplayName or p.Name ;nameLabel.TextColor3=Color3.fromRGB(255,255,255);nameLabel.Font=Enum.Font.GothamBold;nameLabel.TextSize=13;nameLabel.TextXAlignment=Enum.TextXAlignment.Center;Instance.new("UICorner",nameLabel).CornerRadius=UDim.new(0,4);local humanoid=char:FindFirstChildOfClass("Humanoid");if humanoid then local healthFrame=Instance.new("Frame",container);healthFrame.Size=UDim2.new(0,160,0,22);healthFrame.BackgroundColor3=Color3.fromRGB(40,40,40);healthFrame.BackgroundTransparency=0.3;Instance.new("UICorner",healthFrame).CornerRadius=UDim.new(0,4);local healthFill=Instance.new("Frame",healthFrame);healthFill.BackgroundColor3=Color3.fromRGB(0,255,0);Instance.new("UICorner",healthFill).CornerRadius=UDim.new(0,4);local healthText=Instance.new("TextLabel",healthFrame);healthText.Size=UDim2.new(1,0,1,0);healthText.BackgroundTransparency=1;healthText.TextColor3=Color3.fromRGB(255,255,255);healthText.Font=Enum.Font.GothamBold;healthText.TextSize=10;healthText.TextXAlignment=Enum.TextXAlignment.Center;local function updateHealth() local hp=humanoid.Health;local maxHp=humanoid.MaxHealth;local percent=math.clamp(hp/maxHp ,0,1);healthFill.Size=UDim2.new(percent,0,1,0);healthText.Text=string.format("HP: %.0f / %.0f",hp,maxHp);if (percent>0.6) then healthFill.BackgroundColor3=Color3.fromRGB(0,255,50);elseif (percent>0.3) then healthFill.BackgroundColor3=Color3.fromRGB(255,150,0);else healthFill.BackgroundColor3=Color3.fromRGB(255,0,0);end end humanoid:GetPropertyChangedSignal("Health"):Connect(updateHealth);updateHealth();end local distLabel=Instance.new("TextLabel",container);distLabel.Size=UDim2.new(0,160,0,16);distLabel.BackgroundTransparency=0.4;distLabel.BackgroundColor3=Color3.fromRGB(0,0,0);distLabel.TextColor3=Color3.fromRGB(200,200,200);distLabel.Font=Enum.Font.Gotham;distLabel.TextSize=11;distLabel.TextXAlignment=Enum.TextXAlignment.Center;Instance.new("UICorner",distLabel).CornerRadius=UDim.new(0,4);local tools={};if p:FindFirstChild("Backpack") then for _,t in ipairs(p.Backpack:GetChildren()) do if (t:IsA("Tool") and (t.Name:lower()~="fists")) then table.insert(tools,t);end end end if char then for _,t in ipairs(char:GetChildren()) do if (t:IsA("Tool") and (t.Name:lower()~="fists")) then table.insert(tools,t);end end end for _,tool in ipairs(tools) do local name=getRealName(tool);if name then local _,rarityColor=GetWeaponRarity(tool);local lbl=Instance.new("TextLabel",container);lbl.Size=UDim2.new(0,200,0,16);lbl.BackgroundTransparency=0.4;lbl.BackgroundColor3=Color3.fromRGB(0,0,0);lbl.Text=name;lbl.Font=Enum.Font.GothamBold;lbl.TextSize=11;lbl.TextStrokeTransparency=0.4;lbl.TextColor3=rarityColor;lbl.TextXAlignment=Enum.TextXAlignment.Center;Instance.new("UICorner",lbl).CornerRadius=UDim.new(0,4);end end bb.Enabled=true;task.spawn(function() while bb and bb.Parent  do local lChar=LocalPlayer.Character;local lRoot=lChar and lChar:FindFirstChild("HumanoidRootPart") ;local root=char:FindFirstChild("HumanoidRootPart");if (lRoot and root) then local dist=math.floor((lRoot.Position-root.Position).Magnitude);distLabel.Text=string.format("%d meters away",dist);end task.wait(0.5);end end);end local function createESP(p) if (p==LocalPlayer) then return;end local function setup(char) local root=char:WaitForChild("HumanoidRootPart",15);if  not root then return;end if BillboardCache[p] then BillboardCache[p]:Destroy();end local bb=Instance.new("BillboardGui",root);bb.Name="NevoESP";bb.Size=UDim2.new(0,230,0,220);bb.StudsOffset=Vector3.new(0, -3.5,0);bb.AlwaysOnTop=true;bb.MaxDistance=MAX_DISTANCE;local cont=Instance.new("Frame",bb);cont.Name="EspContainer";cont.Size=UDim2.new(1,0,1,0);cont.BackgroundTransparency=1;BillboardCache[p]=bb;updateESP(p);char.ChildAdded:Connect(function(child) if child:IsA("Tool") then task.wait(0.1);updateESP(p);end end);char.ChildRemoved:Connect(function(child) if child:IsA("Tool") then task.wait(0.1);updateESP(p);end end);local backpack=p:WaitForChild("Backpack",5);if backpack then backpack.ChildAdded:Connect(function() updateESP(p);end);backpack.ChildRemoved:Connect(function() updateESP(p);end);end task.spawn(function() while char.Parent and bb.Parent  do updateESP(p);task.wait(UPDATE_INTERVAL);end end);end p.CharacterAdded:Connect(setup);if p.Character then setup(p.Character);end end for _,p in ipairs(Players:GetPlayers()) do createESP(p);end Players.PlayerAdded:Connect(createESP);local function IsFriend(player) return ProtectedFriends[player]==true ;end local function GetTargetInFOV() local closest=nil;local minDist=FOV_RADIUS;local center=Camera.ViewportSize/2 ;for _,player in pairs(Players:GetPlayers()) do if ((player~=LocalPlayer) and  not IsFriend(player) and player.Character) then local targetPart=player.Character:FindFirstChild("Head") or player.Character:FindFirstChild("HumanoidRootPart") ;local humanoid=player.Character:FindFirstChildOfClass("Humanoid");local rootPart=player.Character:FindFirstChild("HumanoidRootPart");if (targetPart and humanoid and (humanoid.Health>0) and rootPart) then local screenPos,onScreen=Camera:WorldToViewportPoint(targetPart.Position);if onScreen then local distToCenter=(Vector2.new(screenPos.X,screenPos.Y) -center).Magnitude;local lpRoot=LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart") ;local worldDist=(lpRoot and (lpRoot.Position-rootPart.Position).Magnitude) or math.huge ;if ((distToCenter<=FOV_RADIUS) and (worldDist<=AIM_RANGE)) then if (distToCenter<minDist) then minDist=distToCenter;closest=targetPart;end end end end end end return closest;end RunService.RenderStepped:Connect(function() if aimbotEnabled then local target=GetTargetInFOV();if target then local targetPos=target.Position;local currentPos=Camera.CFrame.Position;local newCFrame=CFrame.new(currentPos,targetPos);Camera.CFrame=Camera.CFrame:Lerp(newCFrame,AIM_SMOOTHNESS);end end end);RunService.RenderStepped:Connect(function() if FOVCircle then FOVCircle.Position=Camera.ViewportSize/2 ;FOVCircle.Visible=aimbotEnabled;end end);LocalPlayer.CharacterAdded:Connect(function(char) task.wait(0.5);MonitorWeapon();end);MonitorWeapon();local Rayfield=loadstring(game:HttpGet("https://sirius.menu/rayfield"))();local Window=Rayfield:CreateWindow({Name="NEVO SCRIPT",LoadingTitle="NEVO SCRIPT",LoadingSubtitle="Made by Vng",ConfigurationSaving={Enabled=false},Discord={Enabled=false},KeySystem=false});local MainTab=Window:CreateTab("MAIN",4483362458);local FriendsTab=Window:CreateTab("FRIENDS",4483362458);local InfoTab=Window:CreateTab("INFO",4483362458);local AimbotToggle=MainTab:CreateToggle({Name="AIMBOT",CurrentValue=aimbotEnabled,Flag="AimbotToggle",Callback=function(v) aimbotEnabled=v;if FOVCircle then FOVCircle.Visible=aimbotEnabled;end end});local EspToggle=MainTab:CreateToggle({Name="ESP",CurrentValue=espEnabled,Flag="EspToggle",Callback=function(v) espEnabled=v;for _,p in ipairs(Players:GetPlayers()) do updateESP(p);local bb=BillboardCache[p];if bb then bb.Enabled=v;end end end});local AntiShakeToggle=MainTab:CreateToggle({Name="ANTI-SHAKE",CurrentValue=antiShakeEnabled,Flag="AntiShakeToggle",Callback=function(v) antiShakeEnabled=v;end});local FOVSlider=MainTab:CreateSlider({Name="FOV Radius",Range={10,800},Increment=1,Suffix=" Pixels",CurrentValue=FOV_RADIUS,Flag="FOVSlider",Callback=function(Value) FOV_RADIUS=Value;if FOVCircle then FOVCircle.Radius=FOV_RADIUS;end end});MainTab:CreateButton({Name="JOIN DISCORD",Callback=function() setclipboard("https://discord.gg/k-k");Rayfield:Notify({Title="Discord copied",Content="Link copied to clipboard!",Duration=3,Image=4483362458});end});MainTab:CreateButton({Name="CLOSE MENU",Callback=function() Rayfield:Destroy();end});local ProtectedLabel=FriendsTab:CreateParagraph({Title="Protected Players",Content="None"});local function UpdateProtectedLabel() local text="";for player,val in pairs(ProtectedFriends) do if (val and player.Parent) then text=text   .. "- "   .. player.DisplayName   .. " (@"   .. player.Name   .. ")\n" ;end end if (text=="") then text="None";end ProtectedLabel:Set({Title="Protected Players",Content=text});end local PlayerDropdown=FriendsTab:CreateDropdown({Name="Toggle Player Protection",Options={},CurrentOption={},MultipleOptions=false,Flag="PlayerDropdown",Callback=function(Option) local val=((type(Option)=="table") and Option[1]) or Option ;if val then local playerName=string.match(val,"@([%w_]+)");if playerName then local targetPlayer=Players:FindFirstChild(playerName);if targetPlayer then ProtectedFriends[targetPlayer]= not ProtectedFriends[targetPlayer];UpdateProtectedLabel();local status=(ProtectedFriends[targetPlayer] and "PROTECTED") or "UNPROTECTED" ;Rayfield:Notify({Title="Protection Update",Content=targetPlayer.DisplayName   .. " is now "   .. status ,Duration=3,Image=4483362458});end end end end});local function UpdateDropdownOptions() local options={};for _,p in ipairs(Players:GetPlayers()) do if (p~=LocalPlayer) then table.insert(options,p.DisplayName   .. " (@"   .. p.Name   .. ")" );end end PlayerDropdown:Refresh(options,true);end FriendsTab:CreateButton({Name="PROTECT ALL PLAYERS",Callback=function() for _,player in pairs(Players:GetPlayers()) do if (player~=LocalPlayer) then ProtectedFriends[player]=true;end end UpdateProtectedLabel();Rayfield:Notify({Title="Protection Update",Content="All players are now protected!",Duration=3,Image=4483362458});end});FriendsTab:CreateButton({Name="REMOVE ALL PROTECTION",Callback=function() for _,player in pairs(Players:GetPlayers()) do if (player~=LocalPlayer) then ProtectedFriends[player]=nil;end end UpdateProtectedLabel();Rayfield:Notify({Title="Protection Update",Content="All protection has been removed.",Duration=3,Image=4483362458});end});InfoTab:CreateParagraph({Title="NEVO SCRIPT PRO",Content="AIMBOT: Locks on enemy heads\nESP: Shows players name + health + weapon\nANTI-SHAKE: Reduces weapon recoil\nFRIENDS: Protect your friends from aimbot\n\nNevo\nMade by Vng"});local InfoKeyParagraph=InfoTab:CreateParagraph({Title="Info",Content="Press X to open/close menu\nPress Z to toggle Aimbot\nPress R to toggle Anti-Shake"});Players.PlayerAdded:Connect(function() task.wait(1);UpdateDropdownOptions();end);Players.PlayerRemoving:Connect(function(player) ProtectedFriends[player]=nil;UpdateProtectedLabel();UpdateDropdownOptions();end);task.spawn(function() task.wait(1);UpdateDropdownOptions();UpdateProtectedLabel();end);UserInputService.InputBegan:Connect(function(input,gameProcessed) if gameProcessed then return;end if (input.KeyCode==Enum.KeyCode.X) then local gui=game:GetService("CoreGui"):FindFirstChild("Rayfield") or game:GetService("CoreGui"):FindFirstChild("Sirius") or game:GetService("Players").LocalPlayer:WaitForChild("PlayerGui"):FindFirstChild("Rayfield") ;if gui then gui.Enabled= not gui.Enabled;end end if (input.KeyCode==Enum.KeyCode.Z) then aimbotEnabled= not aimbotEnabled;if FOVCircle then FOVCircle.Visible=aimbotEnabled;end if AimbotToggle then AimbotToggle:Set(aimbotEnabled);end end if (input.KeyCode==Enum.KeyCode.R) then antiShakeEnabled= not antiShakeEnabled;if AntiShakeToggle then AntiShakeToggle:Set(antiShakeEnabled);end end end);print("NEVO SCRIPT LOADED - WITH FRIEND LIST!");print("Press X to open/close menu");print("Press Z to toggle Aimbot");print("Press R to toggle Anti-Shake");print("Go to FRIENDS tab to protect players");end LoadMainScript(); end